  ('locality-7c9828ae-moex-00147', 'locality-7c9828ae', 'locality-7c9828ae-moex-112-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '關於法規命令之訂定程序，下列敘述何者正確？', '["雖無法律授權，亦得由機關長官訂定、發布法規命令", "法規命令訂定專屬行政機關職權，一般人民團體不得提議", "雖無急迫情事但為行政效率，法規命令草案無須公告徵求意見", "數機關會同訂定法規命令經上級機關或共同上級機關核定後，應會銜發布"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "63c794400f58", "answer_pdf_sha1": "ae862658c350", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "407", "s": "0711", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
