  ('locality-7c9828ae-moex-00149', 'locality-7c9828ae', 'locality-7c9828ae-moex-112-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '關於行政處分，下列敘述何者錯誤？', '["中央選舉委員會於選舉後為當選之公告，其性質係對選舉結果所為之確認，故該公告為確認處分", "依實務見解，對於違反道路交通管理處罰條例者開具之舉發通知，係為暫時性之行政處分", "基於行政處分之完整性，行政處分只要有一部分無效之情形，該行政處分當然全部無效", "附廢止保留之行政處分，除法律有明文規定者外，於行政機關廢止該行政處分時，人民不得請求信賴保 護之損失補償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "63c794400f58", "answer_pdf_sha1": "ae862658c350", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "407", "s": "0711", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
