  ('locality-7c9828ae-moex-00151', 'locality-7c9828ae', 'locality-7c9828ae-moex-112-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '下列何者非屬行政處分之附款？', '["甲申請於某地經營觀光旅館，主管機關核發許可，並附記：夜間經營產生之噪音不得超過法定標準值", "乙公司申請與他公司為聯合行為，主管機關作成許可處分，並附記：限期1年", "丙申請於某地設置化學工廠，主管機關核發許可，並附記：工廠於0時至上午6時不得操作", "丁申請於某地經營餐廳，主管機關核發許可，並附記：將來有必要時，得命其加裝防止噪音之設備"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "63c794400f58", "answer_pdf_sha1": "ae862658c350", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "407", "s": "0711", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
