  ('locality-7c9828ae-moex-00154', 'locality-7c9828ae', 'locality-7c9828ae-moex-112-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '關於行政程序法規定之公法上請求權，下列敘述何者錯誤？', '["公法上之請求權於請求權人為行政機關時，原則上因5年間不行使而消滅", "公法上請求權之時效，因行政機關為實現該權利所作成之行政處分而中斷", "公法上之請求權於請求權人為人民時，原則上因5年間不行使而消滅", "公法上請求權因時效完成而當然消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "63c794400f58", "answer_pdf_sha1": "ae862658c350", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "407", "s": "0711", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL)
